1	import { describe, it, expect } from "vitest";
2	import { calculatePremium, processClaim } from "./claim-office.js";
3	
4	describe("MHPCO Claim Office - Premium Calculation", () => {
5	  it("should return 5 G processing fee for empty policy", () => {
6	    expect(calculatePremium([])).toBe(5);
7	  });
8	  it("should calculate base premium for single Sword item", () => {
9	    expect(calculatePremium([{ type: "Sword" }])).toBe(105);
10	  });
11	  it("should return 65 G for a single amulet (60 G base + 5 G fee)", () => {
12	    expect(calculatePremium([{ type: "Amulet" }])).toBe(65);
13	  });
14	  it("should return 85 G for a single staff (80 G base + 5 G fee)", () => {
15	    expect(calculatePremium([{ type: "Staff" }])).toBe(85);
16	  });
17	  it("should return 45 G for a single potion (40 G base + 5 G fee)", () => {
18	    expect(calculatePremium([{ type: "Potion" }])).toBe(45);
19	  });
20	  it("should sum base premiums for two different items (sword 100 + amulet 60 = 160 base + 5 fee = 165)", () => {
21	    expect(calculatePremium([{ type: "Sword" }, { type: "Amulet" }])).toBe(165);
22	  });
23	  it("should sum base premiums for three different items (sword 100 + amulet 60 + staff 80 = 240 base + 5 fee = 245)", () => {
24	    expect(calculatePremium([{ type: "Sword" }, { type: "Amulet" }, { type: "Staff" }])).toBe(245);
25	  });
26	  it("should apply 50% cursed surcharge to item base premium (sword 100 base + 50 cursed = 150 total item premium + 5 fee = 155)", () => {
27	    expect(calculatePremium([{ type: "Sword", cursed: true }])).toBe(155);
28	  });
29	  it("should apply 30% high-enchantment surcharge for enchantment >= 5 (sword 100 base + 30 surcharge = 130 item premium + 5 fee = 135)", () => {
30	    expect(calculatePremium([{ type: "Sword", enchantment: 5 }])).toBe(135);
31	  });
32	  it("should apply 20% loyalty discount for customers with >= 2 years (policy base 160 G with 2-year customer: 160 - 32 = 128 + 5 fee = 133)", () => {
33	    expect(calculatePremium([{ type: "Sword" }, { type: "Amulet" }], { yearsAsCustomer: 2 })).toBe(133);
34	  });
35	  it("should apply 10% first insurance surcharge for customers with 0 years (policy base 100 G: 100 + 10 = 110 + 5 fee = 115)", () => {
36	    expect(calculatePremium([{ type: "Sword" }], { yearsAsCustomer: 0 })).toBe(115);
37	  });
38	  it("should apply 15% follow-up contract discount for customers' 2nd+ quote (policy base 100 G with 2nd quote: 100 - 15 = 85 + 5 fee = 90)", () => {
39	    expect(calculatePremium([{ type: "Sword" }], { yearsAsCustomer: 1, isFollowUpQuote: true })).toBe(90);
40	  });
41	  it.todo("should add 5 G processing fee at the end");
42	  it("should round up final premium in MHPCO's favor (197.5 G rounds up to 198 G)", () => {
43	    expect(calculatePremium([{ type: "Potion", cursed: true }], { yearsAsCustomer: 1, isFollowUpQuote: true })).toBe(198);
44	  });
45	  it("should handle multiple items with different modifiers (sword cursed 100+50=150, amulet plain 60, staff enchanted 80+24=104: total 314 base + 5 fee)", () => {
46	    expect(calculatePremium([
47	      { type: "Sword", cursed: true },
48	      { type: "Amulet" },
49	      { type: "Staff", enchantment: 5 }
50	    ])).toBe(319);
51	  });
52	});
53	
54	describe("MHPCO Claim Office - Claim Processing", () => {
55	  it("should apply 100 G deductible per damage event (sword damage 500 G: payout 400 G)", () => {
56	    expect(processClaim([{ type: "Sword" }], [500], 500)).toBe(400);
57	  });
58	  it.todo("should not exceed 2x insurance value in reimbursement");
59	  it.todo("should pay full amount for dragon material items");
60	  it.todo("should pay 50% for highly enchanted items (≥8)");
61	  it.todo("should round payout down (floor) to nearest G");
62	  it.todo("should reject claim for unknown item type");
63	  it.todo("should reject claim for item not in policy");
64	  it.todo("should reject claim with negative damage amount");
65	  it.todo("should reject claim with more damage entries than items");
66	});
67	
68	describe("MHPCO Claim Office - Component Handling", () => {
69	  it("should calculate base premium for single rune component (25 G premium per component)", () => {
70	    expect(calculatePremium([{ type: "Rune" }])).toBe(30);
71	  });
72	  it("should calculate base premium for single moonstone component (25 G premium per component)", () => {
73	    expect(calculatePremium([{ type: "Moonstone" }])).toBe(30);
74	  });
75	  it("should apply special block pricing for exactly 3 identical components (3 runes: 60 G base premium instead of 75 G)", () => {
76	    expect(calculatePremium([{ type: "Rune" }, { type: "Rune" }, { type: "Rune" }])).toBe(65);
77	  });
78	});
