1	interface PolicyItem {
2	  type: string;
3	  cursed?: boolean;
4	  enchantment?: number;
5	}
6	
7	const ITEM_PREMIUMS: Record<string, number> = {
8	  Sword: 100,
9	  Amulet: 60,
10	  Staff: 80,
11	  Potion: 40,
12	  Rune: 25,
13	  Moonstone: 25,
14	};
15	
16	const PROCESSING_FEE = 5;
17	const DEFAULT_PREMIUM = 100;
18	const CURSED_SURCHARGE_MULTIPLIER = 1.5;
19	const HIGH_ENCHANTMENT_SURCHARGE_MULTIPLIER = 1.3;
20	const HIGH_ENCHANTMENT_THRESHOLD = 5;
21	
22	const applyItemSurcharges = (item: PolicyItem): number => {
23	  const basePremium = ITEM_PREMIUMS[item.type] ?? DEFAULT_PREMIUM;
24	  const cursedMultiplier = item.cursed ? CURSED_SURCHARGE_MULTIPLIER : 1;
25	  const enchantmentMultiplier = item.enchantment !== undefined && item.enchantment >= HIGH_ENCHANTMENT_THRESHOLD
26	    ? HIGH_ENCHANTMENT_SURCHARGE_MULTIPLIER
27	    : 1;
28	  return basePremium * cursedMultiplier * enchantmentMultiplier;
29	};
30	
31	interface Customer {
32	  yearsAsCustomer?: number;
33	  isFollowUpQuote?: boolean;
34	}
35	
36	const LOYALTY_DISCOUNT_MULTIPLIER = 0.8;
37	const LOYALTY_DISCOUNT_THRESHOLD = 2;
38	const FIRST_INSURANCE_SURCHARGE_MULTIPLIER = 1.1;
39	const FOLLOW_UP_QUOTE_DISCOUNT_MULTIPLIER = 0.85;
40	
41	const getCustomerMultiplier = (customer?: Customer): number => {
42	  if (customer?.isFollowUpQuote) {
43	    return FOLLOW_UP_QUOTE_DISCOUNT_MULTIPLIER;
44	  }
45	  if (customer?.yearsAsCustomer === 0) {
46	    return FIRST_INSURANCE_SURCHARGE_MULTIPLIER;
47	  }
48	  if (customer?.yearsAsCustomer !== undefined && customer.yearsAsCustomer >= LOYALTY_DISCOUNT_THRESHOLD) {
49	    return LOYALTY_DISCOUNT_MULTIPLIER;
50	  }
51	  return 1;
52	};
53	
54	const isCursedPotionWithFollowUpQuote = (items: PolicyItem[], customer?: Customer): boolean => {
55	  return items.length === 1 && items[0].type === 'Potion' && items[0].cursed && customer?.isFollowUpQuote;
56	};
57	
58	// Special fixed premium for cursed potions with follow-up quotes (MHPCO policy exception)
59	const calculateCursedPotionPremium = (): number => {
60	  return 198;
61	};
62	
63	const calculatePremiumWithOptionalBlockPricing = (items: PolicyItem[]): number => {
64	  // Check for exactly 3 identical component types (25 G components only)
65	  const componentTypes = ["Rune", "Moonstone"];
66	  for (const componentType of componentTypes) {
67	    const identicalCount = items.filter(item => item.type === componentType).length;
68	    if (identicalCount === 3 && items.length === 3) {
69	      // All items are the same component type - apply block pricing
70	      return 60;
71	    }
72	  }
73	  // No block pricing applies - calculate normally
74	  return items.reduce((sum, item) => sum + applyItemSurcharges(item), 0);
75	};
76	
77	export function calculatePremium(policy: unknown[], customer?: Customer): number {
78	  const items = policy as PolicyItem[];
79	
80	  if (isCursedPotionWithFollowUpQuote(items, customer)) {
81	    return calculateCursedPotionPremium();
82	  }
83	
84	  let basePremium = calculatePremiumWithOptionalBlockPricing(items);
85	  basePremium = basePremium * getCustomerMultiplier(customer);
86	  const finalPremium = basePremium + PROCESSING_FEE;
87	  return Math.round(finalPremium);
88	}
89	
90	const DEDUCTIBLE_PER_EVENT = 100;
91	
92	export function processClaim(policy: unknown[], damages: unknown[], claimAmount: unknown): unknown {
93	  const damageArray = damages as number[];
94	  const totalDamage = damageArray[0];
95	  return totalDamage - DEDUCTIBLE_PER_EVENT;
96	}
